#!/usr/bin/env node
/**
 * Evidence-based coverage report generator (INFRA-22)
 * Run: pnpm coverage:generate
 * Requires: tests/sdk-verification/coverage/vitest-evidence.json
 *   (generated by: pnpm test:sdk --reporter=verbose --reporter=json
 *     --outputFile.json=tests/sdk-verification/coverage/vitest-evidence.json)
 *
 * Reads vitest JSON reporter output to determine which test files ran and passed,
 * then validates the EVIDENCE_MAP attribution against actual execution evidence.
 * Symbols whose mapped test file is absent or failed in evidence → 'deferred'.
 * Symbols whose mapped test file passed → 'live'.
 *
 * Replaces the hand-authored LIVE_SYMBOLS map in generate-report.ts (Phase 27, INFRA-22).
 */
import { readFileSync, writeFileSync, readdirSync, existsSync } from 'node:fs';
import { join, dirname, relative } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '../../..');
const manifestsDir = join(root, 'tools/sdk-surface/manifests');
const evidencePath = join(__dirname, 'vitest-evidence.json');
const outputPath = join(__dirname, 'coverage-report.json');

// Fail fast if evidence file is missing
if (!existsSync(evidencePath)) {
  console.error(`ERROR: vitest-evidence.json not found at ${evidencePath}`);
  console.error('Generate it with:');
  console.error(
    '  pnpm test:sdk --reporter=verbose --reporter=json' +
    ' --outputFile.json=tests/sdk-verification/coverage/vitest-evidence.json'
  );
  process.exit(1);
}

// Load and parse evidence file
const evidence = JSON.parse(readFileSync(evidencePath, 'utf8'));
if (!Array.isArray(evidence.testResults)) {
  console.error('ERROR: vitest-evidence.json is missing testResults array — regenerate it.');
  process.exit(1);
}

// Build set of test files that ran and passed
// Vitest emits absolute paths; normalize to relative from repo root, then strip
// the "tests/sdk-verification/" prefix to match EVIDENCE_MAP format.
const sdkVerificationPrefix = 'tests/sdk-verification/';
const passedFiles = new Set<string>();
for (const result of evidence.testResults) {
  const relFromRoot = relative(root, result.name);
  // Strip "tests/sdk-verification/" prefix → e.g. "sdk/slack-chat.test.ts"
  const key = relFromRoot.startsWith(sdkVerificationPrefix)
    ? relFromRoot.slice(sdkVerificationPrefix.length)
    : relFromRoot;
  if (result.status === 'passed') {
    passedFiles.add(key);
  }
}
console.log(`Evidence: ${passedFiles.size} test files passed.`);

